from __future__ import annotations


def icon(name: str, size: int = 16, color: str = "currentColor", cls: str = "") -> str:
    """Return an inline SVG icon by name. Lucide-style paths."""
    attr = f' class="{cls}"' if cls else ""
    svg = f'<svg width="{size}" height="{size}" viewBox="0 0 24 24" fill="none" stroke="{color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"{attr}>'
    svg += _paths(name)
    svg += '</svg>'
    return svg


